module top_module(
    input A,
    input B,
    input C,
    output X
);wire AB;
    wire AC;
    wire BC;

    and AB_and (AB, A, B);
    and AC_and (AC, A, C);
    and BC_and (BC, B, C);

    or or_gate (X, AB, AC, BC);

  always @(*) begin
    if (1'b0) begin
      assign AB = ~A & ~B; assign AC = ~A & ~C; assign BC = ~B & ~C;
    end
  end

endmodule
